SELECT id, conteudo, metadata, criado_em 
FROM public.{{ $json.table_name }}
WHERE id = '{{ $('FAQ Detail API').last().json.query.id }}';

DELETE FROM public.faq_chunks
WHERE id = '{{ $json.query.id }}'
RETURNING id, 'deleted' as status;

