const inputData = $input.all()[0].json.body;
const { chunk_size, overlap, content } = inputData;
// Add validation
console.log('Input data:', { chunk_size, overlap, content_length: content ? content.length : 'undefined' });
if (!content) {
  return [{ json: { error: 'No content found', received_data: inputData } }];
}
// Simple chunking function
function chunkText(text, maxSize, overlapSize) {
  const chunks = [];
  let startIndex = 0;

  while (startIndex < text.length) {
    // Calculate end index
    let endIndex = startIndex + maxSize;

    // If we're not at the end of the text, try to break at a sentence or word boundary
    if (endIndex < text.length) {
      // Look for sentence endings first
      const sentenceEnd = text.lastIndexOf('.', endIndex);
      const questionEnd = text.lastIndexOf('?', endIndex);
      const exclamationEnd = text.lastIndexOf('!', endIndex);

      const bestSentenceEnd = Math.max(sentenceEnd, questionEnd, exclamationEnd);

      if (bestSentenceEnd > startIndex) {
        endIndex = bestSentenceEnd + 1;
      } else {
        // Fall back to word boundary
        const spaceIndex = text.lastIndexOf(' ', endIndex);
        if (spaceIndex > startIndex) {
          endIndex = spaceIndex;
        }
      }
    }

    // Extract the chunk
    const chunkContent = text.slice(startIndex, endIndex).trim();

    if (chunkContent.length > 0) {
      chunks.push({
        content: chunkContent,
        searchable_text: chunkContent,
        metadata: {
          chunk_index: chunks.length,
          start_pos: startIndex,
          end_pos: endIndex,
          size: chunkContent.length,
          created_at: new Date().toISOString()
        }
      });
    }

    // Move to next chunk with overlap
    startIndex = endIndex - overlapSize;

    // Prevent infinite loop
    if (startIndex >= endIndex) {
      startIndex = endIndex;
    }

    // If we're at or past the end, break
    if (startIndex >= text.length) {
      break;
    }
  }

  return chunks;
}
// Process the chunking
const chunks = chunkText(content, chunk_size, overlap);
console.log("Created " + chunks.length + " chunks");
// Return in n8n format
return chunks.map(chunk => ({ json: chunk }));

